}

function renderSummary(input: ReportInput): string[] {
  const done = input.tasks.filter((task) => task.done).length;
  const open = input.tasks.length - done;
  const totalHours = input.tasks.reduce((sum, task) => sum + task.hours, 0);
  return [
    `Done: ${done}`,
    `Open: ${open}`,
    `Hours: ${formatHours(totalHours)}`,
  ];
}

function renderFooter(input: ReportInput): string[] {
  const done = input.tasks.filter((task) => task.done).length;
  const totalHours = input.tasks.reduce((sum, task) => sum + task.hours, 0);
  return [`${done}/${input.tasks.length} done, ${formatHours(totalHours)} total`];
}

const SECTION_RENDERERS: Record<
  string,
  (input: ReportInput, separator: string, bullet: string) => string[]
> = {
  header: (input, separator) => renderHeader(input, separator),
  tasks: (input, _separator, bullet) => renderTasks(input, bullet),
  summary: (input) => renderSummary(input),
  footer: (input) => renderFooter(input),
};

export function formatReport(input: ReportInput, options?: ReportOptions): string {
  const separator = options?.separator ?? "=";
  const bullet = options?.bullet ?? "-";
  const sections = options?.sections ?? ["header", "tasks", "footer"];

  const lines: string[] = [];
  for (const section of sections) {
    const render = SECTION_RENDERERS[section];
    if (!render) {
      throw new Error(`no renderer for section: ${section}`);
    }
    lines.push(...render(input, separator, bullet));
  }
  return lines.join("\n");
}
